}

export function conditional<TReturn = void>(
  cases: Array<Case<TReturn>>,
  defaultCase?: () => TReturn,
) {
  for (const [expression, callback] of cases) {
    if (expression) {
      return callback();
    }
  }

  return defaultCase?.();
}

/**
